const Ajv = require('ajv');
const fs = require('fs');

const config = JSON.parse(fs.readFileSync('config.json', 'utf8'));
const schema = JSON.parse(fs.readFileSync('schema.json', 'utf8'));

const ajv = new Ajv();
const validate = ajv.compile(schema);
const valid = validate(config);

console.log('Validation result:', valid ? 'PASS' : 'FAIL');
if (!valid) {
  console.log('Errors:', validate.errors);
} else {
  console.log('Config is valid');
  console.log('Name field:', config.name);
  console.log('Version field:', config.version);
}
" 2>&1 || echo "Node/AJV not available, trying alternative validation"

python3 << 'EOF'
import json
import re

# Load files
with open('config.json', 'r') as f:
    config = json.load(f)

with open('schema.json', 'r') as f:
    schema = json.load(f)

# Manual validation
errors = []

# Check required fields
for required_field in schema.get('required', []):
    if required_field not in config:
        errors.append(f"Missing required field: {required_field}")

# Check name field
if 'name' in config:
    if not isinstance(config['name'], str):
        errors.append(f"Field 'name' must be string, got {type(config['name'])}")
    elif len(config['name']) < 1:
        errors.append(f"Field 'name' must have minLength 1")

# Check version field
if 'version' in config:
    if not isinstance(config['version'], str):
        errors.append(f"Field 'version' must be string, got {type(config['version'])}")
    else:
        pattern = schema['properties']['version']['pattern']
        if not re.match(pattern, config['version']):
            errors.append(f"Field 'version' '{config['version']}' does not match pattern '{pattern}'")

# Output results
if errors:
    print("❌ Validation FAILED")
    for error in errors:
        print(f"  - {error}")
else:
    print("✅ Validation PASSED")
    print(f"  - name: {config['name']}")
    print(f"  - version: {config['version']}")
    print(f"  - Pattern match: {bool(re.match(schema['properties']['version']['pattern'], config['version']))}")
EOF
